//#region src/lib/seo.ts
var SITE_URL = (process.env.SITE_URL || process.env.VITE_SITE_URL || "https://theunitedhell.com").replace(/\/$/, "");
var SITE_NAME = "The United Hell";
var SITE_TAGLINE = "Beyond comfort. Beyond headlines.";
var SITE_LOGO = `${SITE_URL}/THEUH.LOGO.png`;
var SITE_DESCRIPTION = "The United Hell brings together the world's most important stories, discoveries, civilizations, innovations, and ideas — transforming information into understanding, curiosity into exploration, and knowledge into progress.";
function canonicalUrl(path) {
	return `${SITE_URL}${path.startsWith("/") ? path : `/${path}`}`;
}
function articleUrl(slug) {
	return canonicalUrl(`/article/${slug}`);
}
function organizationJsonLd() {
	return {
		"@context": "https://schema.org",
		"@type": ["Organization", "NewsMediaOrganization"],
		name: SITE_NAME,
		url: SITE_URL,
		logo: {
			"@type": "ImageObject",
			url: SITE_LOGO,
			width: 512,
			height: 512
		},
		description: SITE_DESCRIPTION,
		sameAs: []
	};
}
function websiteJsonLd() {
	return {
		"@context": "https://schema.org",
		"@type": "WebSite",
		name: SITE_NAME,
		url: SITE_URL,
		description: SITE_DESCRIPTION,
		potentialAction: {
			"@type": "SearchAction",
			target: {
				"@type": "EntryPoint",
				urlTemplate: `${SITE_URL}/search?q={search_term_string}`
			},
			"query-input": "required name=search_term_string"
		}
	};
}
function newsArticleJsonLd(article) {
	return {
		"@context": "https://schema.org",
		"@type": "NewsArticle",
		headline: article.title,
		description: article.dek || article.title,
		url: articleUrl(article.slug),
		image: {
			"@type": "ImageObject",
			url: article.cover_image_url || SITE_LOGO
		},
		datePublished: article.published_at,
		dateModified: article.published_at,
		author: {
			"@type": "Organization",
			name: SITE_NAME
		},
		publisher: {
			"@type": "Organization",
			name: SITE_NAME,
			logo: {
				"@type": "ImageObject",
				url: SITE_LOGO
			}
		},
		articleSection: article.category,
		mainEntityOfPage: {
			"@type": "WebPage",
			"@id": articleUrl(article.slug)
		}
	};
}
function breadcrumbJsonLd(items) {
	return {
		"@context": "https://schema.org",
		"@type": "BreadcrumbList",
		itemListElement: items.map((item, i) => ({
			"@type": "ListItem",
			position: i + 1,
			name: item.name,
			item: item.url
		}))
	};
}
//#endregion
export { SITE_URL as a, canonicalUrl as c, websiteJsonLd as d, SITE_TAGLINE as i, newsArticleJsonLd as l, SITE_LOGO as n, articleUrl as o, SITE_NAME as r, breadcrumbJsonLd as s, SITE_DESCRIPTION as t, organizationJsonLd as u };
